//-------------------------------------------------------------------------
// 엑셓 다운로드
//-------------------------------------------------------------------------
scwin.runExcel = function() {
    let cnt = ds_containerOrthersPrimeCostDTOList.getRowCount();

    if(cnt <= 0 ) {
            $c.win.alert(MSG_CM_WRN_002);
            return;
    } else {
        const options = {
            fileName: "컨테이너별 기타원가 내역 확인.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
            sheetName: "컨테이너별 기타원가 내역 확인",
            startRowIndex : 2
        };

        // 타이틀
        const infoArr = [{
            rowIndex: 0, colIndex: 0, rowSpan: 1, colSpan: 18, text: "컨테이너별 기타원가 내역 확인", textAlign: "center",
            drawBorder: false, fontSize: "18px"
        }
        ];

        $c.data.downloadGridViewExcel(gr_containerOrthersPrimeCostDTOList, options, infoArr);
    }
}

